macros.token:
# Auto-generated by the Galaxy wrapper.

csv_folder = './csv'
output_docs_folder = './out/'
entry_type = '${advanced.entry_type}'
only_process_reads_with_allele_frequency = ${advanced.only_process_reads_with_allele_frequency}
populations_by_allele_counts = ${advanced.populations_by_allele_counts}
reference_genome = '${advanced.reference_genome}'
datasetId = '${dataset_id}'
case_level_data = ${advanced.case_level_data}
exact_heterozygosity = ${advanced.exact_heterozygosity}
num_rows = ${advanced.num_rows}
verbosity = ${advanced.verbosity}

# ── Credentials from Galaxy server config (UNTOUCHED) ──
database_host = '${advanced.database.database_host}'
database_port = ${advanced.database.database_port}
database_name = '${advanced.database.database_name}'

export LC_ALL=C.UTF-8 && export LANG=C.UTF-8 && RUNTIME_ROOT="$(python - <<'PY' import os import conf.conf print(os.path.dirname(os.path.dirname(conf.conf.__file__))) PY )" && rm -rf beacon2_runtime && cp -R "$RUNTIME_ROOT" ./beacon2_runtime && chmod -R u+rwX ./beacon2_runtime && mkdir -p out && # Write config (custom file has highest priority) #if $advanced.custom_conf_py cp '$advanced.custom_conf_py' ./beacon2_runtime/conf/conf.py #elif $custom_conf_py cp '$custom_conf_py' ./beacon2_runtime/conf/conf.py #else cat > ./beacon2_runtime/conf/conf.py << 'EOF' @BEACON2_CONF_BASE_ADVANCED@ # or @BEACON2_CONF_BASE_DBONLY@ depending on the tool EOF #end if # Append credentials (your existing secure logic) python - <<'PY' import json from pathlib import Path credentials_path = Path(r'$credentials') conf_path = Path('beacon2_runtime/conf/conf.py') credentials = json.loads(credentials_path.read_text()) with conf_path.open('a') as handle: handle.write("
database_user = {!r}
".format(credentials.get('db_user', ''))) handle.write("database_password = {!r}
".format(credentials.get('db_password', ''))) handle.write("database_auth_source = {!r}
".format(credentials.get('db_auth_source', 'admin'))) PY

